# --- Sensitive Data Redaction ---

SENSITIVE_FIELDS = {
    'password', 'passwd', 'secret', 'token', 'authorization',
    'access_token', 'refresh_token', 'api_key', 'apikey',
    'credit_card', 'card_number', 'cvv', 'ssn', 'social_security',
    'private_key', 'cookie', 'session_id', 'csrf_token',
}

SENSITIVE_HEADER_KEYS = {
    'authorization', 'cookie', 'x-api-key', 'x-auth-token',
    'proxy-authorization', 'x-csrf-token',
}


def redact_value(value, visible_chars=0):
    """Redact a sensitive value, optionally showing last N chars."""
    if not value:
        return '***REDACTED***'
    if visible_chars > 0 and len(str(value)) > visible_chars:
        return f'***REDACTED***...{str(value)[-visible_chars:]}'
    return '***REDACTED***'


def redact_dict(data, sensitive_keys=None):
    """Recursively redact sensitive fields from a dictionary."""
    if sensitive_keys is None:
        sensitive_keys = SENSITIVE_FIELDS

    if isinstance(data, dict):
        redacted = {}
        for key, value in data.items():
            if key.lower() in sensitive_keys:
                redacted[key] = redact_value(value)
            elif isinstance(value, (dict, list)):
                redacted[key] = redact_dict(value, sensitive_keys)
            else:
                redacted[key] = value
        return redacted
    elif isinstance(data, list):
        return [redact_dict(item, sensitive_keys) for item in data]
    return data


def redact_headers(headers):
    """Redact sensitive headers."""
    redacted = {}
    for key, value in headers.items():
        if key.lower() in SENSITIVE_HEADER_KEYS:
            # Show type of auth but not the credential
            if key.lower() == 'authorization' and ' ' in value:
                scheme = value.split(' ')[0]
                redacted[key] = f'{scheme} ***REDACTED***'
            else:
                redacted[key] = redact_value(value)
        else:
            redacted[key] = value
    return redacted


# --- Custom Log Formatter ---

class RequestFormatter(logging.Formatter):
    """Custom formatter that includes request context information."""

    def format(self, record):
        if has_request_context():
            record.url = request.url
            record.method = request.method
            record.remote_addr = request.remote_addr
            record.request_id = getattr(g, 'request_id', 'N/A')
            record.user_id = getattr(g, 'user_id', 'anonymous')
        else:
            record.url = 'N/A'
            record.method = 'N/A'
            record.remote_addr = 'N/A'
            record.request_id = 'N/A'
            record.user_id = 'N/A'
        return super().format(record)


class SensitiveDataFilter(logging.Filter):
    """Logging filter that redacts sensitive patterns from log messages."""

    # Patterns for common sensitive data in free text
    PATTERNS = [
        (re.compile(r'(password["\s:=]+)[^\s,}"\']+', re.IGNORECASE), r'\1***REDACTED***'),
        (re.compile(r'(token["\s:=]+)[^\s,}"\']+', re.IGNORECASE), r'\1***REDACTED***'),
        (re.compile(r'(Bearer\s+)[^\s,}"\']+', re.IGNORECASE), r'\1***REDACTED***'),
        (re.compile(r'(api[_-]?key["\s:=]+)[^\s,}"\']+', re.IGNORECASE), r'\1***REDACTED***'),
        (re.compile(r'\b\d{4}[-\s]?\d{4}[-\s]?\d{4}[-\s]?\d{4}\b'), '***CARD_REDACTED***'),
    ]

    def filter(self, record):
        if isinstance(record.msg, str):
            for pattern, replacement in self.PATTERNS:
                record.msg = pattern.sub(replacement, record.msg)
        if record.args:
            new_args = []
            for arg in (record.args if isinstance(record.args, tuple) else (record.args,)):
                if isinstance(arg, str):
                    for pattern, replacement in self.PATTERNS:
                        arg = pattern.sub(replacement, arg)
                new_args.append(arg)
            record.args = tuple(new_args)
        return True


