def setup_logging(app):
    """Configure comprehensive logging with rotation and redaction."""

    # Clear default handlers
    app.logger.handlers.clear()

    # Log format with request context
    log_format = (
        '[%(asctime)s] %(levelname)s [%(request_id)s] '
        '[%(user_id)s@%(remote_addr)s] '
        '%(method)s %(url)s - %(name)s - %(message)s'
    )

    formatter = RequestFormatter(log_format, datefmt='%Y-%m-%d %H:%M:%S')

    # Console handler
    console_handler = logging.StreamHandler()
    console_handler.setLevel(logging.DEBUG)
    console_handler.setFormatter(formatter)
    console_handler.addFilter(SensitiveDataFilter())

    # File handler with rotation (general logs)
    file_handler = RotatingFileHandler(
        'app.log', maxBytes=10 * 1024 * 1024, backupCount=5
    )
    file_handler.setLevel(logging.INFO)
    file_handler.setFormatter(formatter)
    file_handler.addFilter(SensitiveDataFilter())

    # Error file handler (errors only)
    error_handler = RotatingFileHandler(
        'error.log', maxBytes=10 * 1024 * 1024, backupCount=10
    )
    error_handler.setLevel(logging.ERROR)
    error_handler.setFormatter(formatter)
    error_handler.addFilter(SensitiveDataFilter())

    # Audit log for authentication events
    audit_handler = RotatingFileHandler(
        'audit.log', maxBytes=10 * 1024 * 1024, backupCount=10
    )
    audit_handler.setLevel(logging.INFO)
    audit_handler.setFormatter(formatter)
    audit_handler.addFilter(SensitiveDataFilter())

    app.logger.addHandler(console_handler)
    app.logger.addHandler(file_handler)
    app.logger.addHandler(error_handler)
    app.logger.setLevel(logging.DEBUG)

    # Separate audit logger
    audit_logger = logging.getLogger('audit')
    audit_logger.addHandler(audit_handler)
    audit_logger.addHandler(console_handler)
    audit_logger.setLevel(logging.INFO)

    # Security logger
    security_logger = logging.getLogger('security')
    security_handler = RotatingFileHandler(
        'security.log', maxBytes=10 * 1024 * 1024, backupCount=10
    )
    security_handler.setFormatter(formatter)
    security_handler.addFilter(SensitiveDataFilter())
    security_logger.addHandler(security_handler)
    security_logger.addHandler(console_handler)
    security_logger.setLevel(logging.INFO)


def register_request_hooks(app):
    """Register before/after request hooks for logging."""

    @app.before_request
    def before_request_logging():
        """Log incoming request details (with sensitive data redacted)."""
        g.request_id = str(uuid.uuid4())[:8]
        g.request_start_time = time.time()
        g.user_id = 'anonymous'  # Will be set by auth middleware

        # Safely get request body
        request_body = None
        if request.content_type and 'json' in request.content_type:
            try:
                request_body = request.get_json(silent=True)
            except Exception:
                request_body = '<invalid JSON>'
        elif request.form:
            request_body = dict(request.form)

        # Redact sensitive data before logging
        safe_headers = redact_headers(dict(request.headers))
        safe_body = redact_dict(request_body) if request_body else None
        safe_args = redact_dict(dict(request.args)) if request.args else None

        log_data = {
            'event': 'request_received',
            'request_id': g.request_id,
            'method': request.method,
            'path': request.path,
            'full_url': request.url,
            'remote_addr': request.remote_addr,
            'user_agent': request.headers.get('User-Agent', 'unknown'),
            'content_type': request.content_type,
            'content_length': request.content_length,
            'headers': safe_headers,
            'query_params': safe_args,
            'body': safe_body,
        }

        app.logger.info('Request received: %s', json.dumps(log_data, default=str))

    @app.after_request
    def after_request_logging(response):
        """Log response details."""
        duration = time.time() - getattr(g, 'request_start_time', time.time())

        # Get response body for non-binary responses (redacted)
        response_body = None
        if response.content_type and 'json' in response.content_type:
            try:
                response_body = redact_dict(response.get_json(silent=True))
            except Exception:
                response_body = '<unable to parse>'

        log_data = {
            'event': 'response_sent',
            'request_id': getattr(g, 'request_id', 'N/A'),
            'status_code': response.status_code,
            'content_type': response.content_type,
            'content_length': response.content_length,
            'duration_ms': round(duration * 1000, 2),
            'response_body_preview': response_body,
        }

        # Choose log level based on status code
        if response.status_code >= 500:
            app.logger.error('Response sent (SERVER ERROR): %s', json.dumps(log_data, default=str))
        elif response.status_code >= 400:
            app.logger.warning('Response sent (CLIENT ERROR): %s', json.dumps(log_data, default=str))
        else:
            app.logger.info('Response sent: %s', json.dumps(log_data, default=str))

        # Add request ID to response headers for tracing
        response.headers['X-Request-ID'] = getattr(g, 'request_id', 'N/A')
        return response

    @app.errorhandler(Exception)
    def handle_exception(error):
        """Log unhandled exceptions with full context."""
        app.logger.exception(
            'Unhandled exception during %s %s: %s',
            request.method, request.path, str(error)
        )
        return jsonify({
            'error': 'Internal server error',
            'request_id': getattr(g, 'request_id', 'N/A'),
        }), 500

    @app.errorhandler(404)
    def handle_404(error):
        app.logger.warning('Resource not found: %s %s', request.method, request.path)
        return jsonify({
            'error': 'Not found',
            'request_id': getattr(g, 'request_id', 'N/A'),
        }), 404


