def log_auth_event(event_type, username, success, reason=None, extra=None):
    """
    Log authentication events to the audit log.
    NOTE: We NEVER log the actual password or token — only metadata about the attempt.
    """
    audit_logger = logging.getLogger('audit')

    log_data = {
        'event': event_type,
        'timestamp': datetime.now(timezone.utc).isoformat(),
        'username': username,
        'success': success,
        'source_ip': request.remote_addr if has_request_context() else 'N/A',
        'user_agent': request.headers.get('User-Agent', 'unknown') if has_request_context() else 'N/A',
        'request_id': getattr(g, 'request_id', 'N/A') if has_request_context() else 'N/A',
    }

    if reason:
        log_data['failure_reason'] = reason  # e.g., "invalid_password", "user_not_found"

    if extra:
        log_data.update(extra)

    if success:
        audit_logger.info('AUTH_EVENT: %s', json.dumps(log_data))
    else:
        audit_logger.warning('AUTH_EVENT (FAILED): %s', json.dumps(log_data))

        # Log to security logger for failed attempts
        security_logger = logging.getLogger('security')
        security_logger.warning('FAILED_AUTH: %s', json.dumps(log_data))


def require_auth(f):
    """Decorator to require authentication via Bearer token."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            log_auth_event('token_auth', 'unknown', False, reason='missing_or_invalid_auth_header')
            return jsonify({'error': 'Authorization required'}), 401

        # In a real app, validate JWT token here
        # We log that validation occurred, NOT the token itself
        token = auth_header.split(' ', 1)[1]

        # Simulate token validation
        if token == 'valid-token-admin':
            g.user_id = 'usr_001'
            g.username = 'admin'
            g.role = 'admin'
        elif token == 'valid-token-user':
            g.user_id = 'usr_002'
            g.username = 'user1'
            g.role = 'user'
        else:
            log_auth_event(
                'token_auth', 'unknown', False,
                reason='invalid_token',
                extra={
                    # Log token fingerprint for debugging, NOT the full token
                    'token_prefix': token[:4] + '...' if len(token) > 4 else '***',
                    'token_length': len(token),
                }
            )
            return jsonify({'error': 'Invalid token'}), 401

        log_auth_event('token_auth', g.username, True)
        return f(*args, **kwargs)

    return decorated


